import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { useAuthStore } from "@/stores/auth.store";
import { SubmitHandler, useForm } from "react-hook-form";
import { ProfileUpdatePayload } from "../types/profile.types";
import { Button } from "@/components/ui/button";
import { Save } from "lucide-react";
import { useProfileActions } from "../hooks/useProfileActions";
import { Spinner } from "@/components/ui/spinner";

export function PersonalInformationsForm() {
  const { user } = useAuthStore();
  const { updateProfile, loading, apiError, clearApiError } =
    useProfileActions();

  const form = useForm<ProfileUpdatePayload>({
    defaultValues: {
      name: user?.name,
      email: user?.email,
    },
  });

  const handleSubmit: SubmitHandler<ProfileUpdatePayload> = async (values) => {
    clearApiError();
    try {
      await updateProfile(values);
      form.reset();
    } catch (err) {}
  };

  return (
    <Form {...form}>
      <form
        id="updateProfileForm"
        onSubmit={form.handleSubmit(handleSubmit)}
        className="space-y-6 mt-3 mb-2"
      >
        <FormFieldGrid
                  label="New Password Confirm"
                  description="Confirm your new password"
                >
                  
                </FormFieldGrid>
          <FormField
            control={form.control}
            name="name"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Name</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Email</FormLabel>
                <FormControl>
                  <Input {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

        <div className="w-full flex justify-end">
          <Button form="updateProfileForm" disabled={!!loading}>
            {!loading && (
              <>
                <Save className="h-3 w-3" />
                Save
              </>
            )}

            {loading && (
              <>
                <Spinner className="w-8" />
                Submitting
              </>
            )}
          </Button>
        </div>
      </form>
    </Form>
  );
}
